// stores/authStore.js
import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export const useAuthStore = create(
  persist(
    (set, get) => ({
      // État
      user: null,           // Objet utilisateur { id, email, name, role }
      token: null,          // JWT access token
      isAuthenticated: false,

      // Actions
      login: (userData, token) => set({ 
        user: userData, 
        token, 
        isAuthenticated: true 
      }),

      logout: () => set({ 
        user: null, 
        token: null, 
        isAuthenticated: false 
      }),

      // Sélecteur pour vérifier si l'utilisateur est admin
      isAdmin: () => get().user?.role === 'admin',
    }),
    {
      name: 'auth-storage', // clé dans localStorage
      partialize: (state) => ({ token: state.token, user: state.user }),
    }
  )
);
```

**Approche 1 : Redirection fixe**
```jsx
// Après connexion
navigate('/account');
```
Avantages : simple à implémenter.
Inconvénients : l'utilisateur perd le contexte de sa navigation. S'il essayait d'accéder à `/checkout` et a été redirigé vers `/login`, après connexion il arrive sur `/account` au lieu de `/checkout`.

**Approche 2 : Redirection dynamique avec location.state**
```jsx
// Dans ProtectedRoute
<Navigate to="/login" state={{ from: location.pathname }} replace />

// Dans LoginPage après connexion
const location = useLocation();
const from = location.state?.from || '/account';
navigate(from, { replace: true });
```
Avantages : expérience utilisateur améliorée, retour au contexte initial.
Inconvénients : nécessite de passer et récupérer l'état, plus de code.

**Approche 3 : Stockage dans sessionStorage**
Alternative où l'URL de retour est stockée dans sessionStorage avant redirection vers login, puis récupérée après connexion. Utile pour les redirections complexes.

**Recommandation** : Utiliser l'approche 2 avec `location.state` car elle est native à React Router, respecte le flux de navigation, et offre la meilleure UX.
